import type { Request } from 'express';
import { pool } from '../db/client.js';

export type AuditAction =
  | 'auth.login'
  | 'auth.login_failed'
  | 'auth.logout'
  | 'auth.caia_login'
  | 'auth.caia_login_failed'
  | 'session.created'
  | 'session.refreshed'
  | 'session.terminated'
  | 'session.expired'
  | 'invite.accept_caia'
  | 'token.created'
  | 'token.revoked'
  | 'token.used'
  | 'api_token.created'
  | 'api_token.revoked'
  | 'api_token.used'
  | 'auth.workspace_access_revoked'
  | 'auth.workspace_admin_denied'
  | string;

export interface AuditRequestContext {
  req?: Request;
  workspaceId?: string | null;
  actorUserId?: string | null;
  impersonatingUserId?: string | null;
}

export interface AuditWriteInput extends AuditRequestContext {
  action: AuditAction;
  resourceType?: string | null;
  resourceId?: string | null;
  details?: Record<string, unknown> | null;
}

export interface AuditEventInput {
  workspaceId?: string | null;
  /** User ID of the actor. Optional for failed login attempts where user is unknown. */
  actorUserId?: string | null;
  impersonatingUserId?: string | null;
  action: AuditAction;
  resourceType?: string | null;
  resourceId?: string | null;
  details?: Record<string, unknown> | null;
  req?: Request;
}

export type AuthAuditContext = AuditRequestContext;

function getRequestContext(req?: Request): { ipAddress: string | null; userAgent: string | null } {
  return {
    ipAddress: req?.ip || req?.socket?.remoteAddress || null,
    userAgent: req?.get('user-agent') || null,
  };
}

export async function logAuditEvent(input: AuditEventInput): Promise<void> {
  const { workspaceId, actorUserId, impersonatingUserId, action, resourceType, resourceId, details, req } = input;
  const { ipAddress, userAgent } = getRequestContext(req);

  try {
    await pool.query(
      `INSERT INTO audit_logs (workspace_id, actor_user_id, impersonating_user_id, action, resource_type, resource_id, details, ip_address, user_agent)
       VALUES ($1, $2, $3, $4, $5, $6, $7, $8, $9)`,
      [workspaceId || null, actorUserId || null, impersonatingUserId || null, action, resourceType || null, resourceId || null, details ? JSON.stringify(details) : null, ipAddress, userAgent]
    );
  } catch (error) {
    // Log but don't fail the request if audit logging fails
    console.error('Failed to log audit event:', error);
  }
}

export function auditAuthEvent(
  action: 'auth.login' | 'auth.login_failed' | 'auth.logout' | 'auth.caia_login' | 'auth.caia_login_failed' | 'session.expired' | 'auth.workspace_access_revoked' | 'auth.workspace_admin_denied',
  context: AuthAuditContext,
  details?: Record<string, unknown> | null
) {
  return logAuditEvent({ ...context, action, details });
}

export function auditSessionEvent(
  action: 'session.created' | 'session.refreshed' | 'session.terminated' | 'session.expired',
  context: AuthAuditContext,
  details?: Record<string, unknown> | null
) {
  return logAuditEvent({ ...context, action, details });
}

export function auditSessionLifecycleEvent(
  action: 'session.created' | 'session.refreshed' | 'session.terminated' | 'session.expired',
  context: AuthAuditContext,
  details?: Record<string, unknown> | null
) {
  return logAuditEvent({ ...context, action, details });
}

export function auditSessionLifecycleEvent(
  action: 'session.created' | 'session.refreshed' | 'session.terminated' | 'session.expired',
  context: AuthAuditContext,
  details?: Record<string, unknown> | null
) {
  return logAuditEvent({ ...context, action, details });
}

export function auditTokenEvent(
  action: 'token.created' | 'token.revoked' | 'token.used' | 'api_token.created' | 'api_token.revoked' | 'api_token.used',
  context: AuthAuditContext,
  resource: { type: string; id?: string | null },
  details?: Record<string, unknown> | null
) {
  return logAuditEvent({
    ...context,
    action,
    resourceType: resource.type,
    resourceId: resource.id,
    details,
  });
}

export function auditSecurityEvent(
  action: AuditAction,
  context: AuditRequestContext,
  details?: Record<string, unknown> | null,
  resource?: { type?: string | null; id?: string | null }
) {
  return logAuditEvent({
    ...context,
    action,
    resourceType: resource?.type ?? null,
    resourceId: resource?.id ?? null,
    details,
  });
}

