  getTokenFromRequest: (req) => req.headers['x-csrf-token'] as string,
});

const isBearerRequest = (req: Request) => Boolean(req.headers?.authorization?.startsWith('Bearer '));

const conditionalCsrf = (req: Request, res: Response, next: NextFunction) => {
  if (isBearerRequest(req)) {
    return next();
  }

  return csrfSynchronisedProtection(req, res, next);
};

const loginLimiter = rateLimit({
  windowMs: 15 * 60 * 1000,
  max: isTestEnv ? 1000 : 5,
  standardHeaders: true,
  legacyHeaders: false,
  message: { error: 'Too many login attempts. Try again in 15 minutes.' },
  skipSuccessfulRequests: true,
  skip: isBearerRequest,
});

const apiLimiter = rateLimit({
  windowMs: 60 * 1000,
  max: isTestEnv ? 10000 : isDevEnv ? 1000 : 100,
  standardHeaders: true,
  legacyHeaders: false,
  message: { error: 'Too many requests. Please slow down.' },
  skip: isBearerRequest,
});

